mapper.sql:
from aiw_investment_analysis_report r
where 1 = 1

    and r.market_scope = #{criteria.marketScope}


    and r.theme_code = #{criteria.themeCode}


    and r.provider_code = #{criteria.providerCode}


    and r.status = #{criteria.status}

mapper.select:
select r.* 
order by ${sortColumn}

    asc
    desc

limit #{offset}, #{criteria.size}
